const getRandomNudge = () => NUDGE_TITLES[Math.floor(Math.random() * NUDGE_TITLES.length)];

export default function TaskTreeApp() {
  const [userHash, setUserHashState] = useState(() => getUserHash());

  const handleLogout = () => {
    resetClient();
    clearUserHash();
    setUserHashState('');
  };

  if (!userHash) {
    return <SecretScreen onAuthenticated={(hash) => setUserHashState(hash)} />;
  }

  return <AppContent key={userHash} onLogout={handleLogout} />;
}

function AppContent({ onLogout }) {
  const isMobile = useIsMobile();
  const onlineStatus = useOnlineStatus();
  const { isOnline } = onlineStatus;
  const treeDataHook = useTreeData();
  const logsHook = useLogs();
  const memoryDataHook = useMemoryData();
  const themeValue = useTheme();

  const { treeData, handleUpdate, handleUpdateField, handleAddField } = treeDataHook;
  const productivityStats = useProductivityStats(treeData, logsHook.logs);

  // Load settings from Supabase on mount
  useEffect(() => {
    initSettingsFromSupabase();
  }, []);

  // Replay queued offline operations one by one.
  // On failure, saves remaining ops back and returns false.
  const replayPendingOps = async () => {
    const ops = getPendingOps();
    if (ops.length === 0) return true;

    for (let i = 0; i < ops.length; i++) {
      const op = ops[i];
      try {
        switch (op.type) {
          case 'createLog': await api.createLog(op.payload); break;
          case 'updateLog': await api.updateLog(op.payload.id, op.payload.updates); break;
          case 'deleteLog': await api.deleteLog(op.payload.id); break;
          case 'createNote': await api.createNote(op.payload); break;
          case 'updateNote': await api.updateNote(op.payload.id, op.payload.text); break;
          case 'deleteNote': await api.deleteNote(op.payload.id); break;
          case 'createQA': await api.createQA(op.payload); break;
          case 'updateQA': await api.updateQA(op.payload.id, op.payload.updates); break;
          case 'deleteQA': await api.deleteQA(op.payload.id); break;
          default: break;
        }
      } catch (err) {
        console.error('Replay failed for op:', op, err);
        // Save remaining (unplayed) ops back and stop
        savePendingOps(ops.slice(i));
        return false;
      }
    }
    clearPendingOps();
    return true;
  };

  // Replay pending ops and force-sync when coming back online or on initial load
  const wasOnlineRef = useRef(false);
  useEffect(() => {
    if (isOnline && !wasOnlineRef.current) {
      // Transitioned from offline → online, or initial load while online
      const replay = async () => {
        await replayPendingOps();
        // Force-sync all hooks (merge-based, both sides' edits survive)
        try { await treeDataHook.forceSync(); } catch (e) { console.error('Tree sync failed:', e); }
        try { await logsHook.forceSync(); } catch (e) { console.error('Logs sync failed:', e); }
        try { await memoryDataHook.forceSync(); } catch (e) { console.error('Memory sync failed:', e); }
      };
      replay();
    }
    wasOnlineRef.current = isOnline;
  }, [isOnline]);

  // Periodic background sync — every 5 minutes when online, replay pending ops
  useEffect(() => {
    if (!isOnline) return;
    const interval = setInterval(async () => {
      const success = await replayPendingOps();
      if (!success) onlineStatus.markUnreachable();
    }, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, [isOnline, onlineStatus]);

  const [petEnabled, setPetEnabled] = useState(() => localStorage.getItem('flow-pet-enabled') !== 'false');
  const [petSkin, setPetSkin] = useState(() => localStorage.getItem('flow-pet-skin') || 'default');
  const [bgEmojis, setBgEmojis] = useState(() => {
    const raw = localStorage.getItem('flow-bg-emojis') || '';
    return raw.trim() ? raw.trim().split(/\s+/) : null;
  });

  useEffect(() => {
    const sync = () => {
      setPetEnabled(localStorage.getItem('flow-pet-enabled') !== 'false');
      setPetSkin(localStorage.getItem('flow-pet-skin') || 'default');
      const raw = localStorage.getItem('flow-bg-emojis') || '';
      setBgEmojis(raw.trim() ? raw.trim().split(/\s+/) : null);
    };
    window.addEventListener('flow-vibes-changed', sync);
    return () => window.removeEventListener('flow-vibes-changed', sync);
  }, []);

  const [focusedTaskId, setFocusedTaskId] = useState(null);
  const [timerMode, setTimerMode] = useState('pomodoro');
  const [timeRemaining, setTimeRemaining] = useState(() => getTimerDurations().pomodoro);
  const [isTimerActive, setIsTimerActive] = useState(false);
  const [pomodoroCount, setPomodoroCount] = useState(0);
  const [activeSession, setActiveSession] = useState(null);
  const [capturedTasks, setCapturedTasks] = useState([]);
  const [showTriageModal, setShowTriageModal] = useState(false);

  // Refs for notification action handlers
  const swRegistrationRef = useRef(null);
  const handleUpdateRef = useRef(handleUpdate);
  const focusedTaskIdRef = useRef(focusedTaskId);
  const nudgeTimeoutRef = useRef(null);
  handleUpdateRef.current = handleUpdate;
  focusedTaskIdRef.current = focusedTaskId;

  const focusedTask = useMemo(() => {
    if (!focusedTaskId) return null;
    return findNodeRecursive(treeData, focusedTaskId);
  }, [treeData, focusedTaskId]);

  // Register service worker for notification actions
  useEffect(() => {
    if (!('serviceWorker' in navigator)) return;

    navigator.serviceWorker.register(`${process.env.PUBLIC_URL}/notification-sw.js`)
      .then(reg => { swRegistrationRef.current = reg; })
      .catch(err => console.error('Notification SW registration failed:', err));

    const handleMessage = (event) => {
      if (event.data?.type === 'NOTIFICATION_ACTION') {
        const { action, taskId } = event.data;
        window.focus();

        if (action === 'newPomodoro') {
          const tid = taskId || focusedTaskIdRef.current;
          if (tid) {
            setFocusedTaskId(tid);
            setTimerMode('pomodoro');
            setTimeRemaining(getTimerDurations().pomodoro);
            setIsTimerActive(true);
            setActiveSession({ taskId: tid, startTime: new Date() });
          }
        } else if (action === 'markFinished') {
          const tid = taskId || focusedTaskIdRef.current;
          if (tid) {
            handleUpdateRef.current(tid, { isCompleted: true });
          }
          setIsTimerActive(false);
          setActiveSession(null);
          setFocusedTaskId(null);
        } else if (action === 'snooze') {
          // Snooze nudge for 10 minutes
          clearTimeout(nudgeTimeoutRef.current);
          nudgeTimeoutRef.current = setTimeout(() => {
            showNotification(
              getRandomNudge(),
              "You haven't started this in a while.",
              [{ action: 'snooze', title: 'Remind in 10 min' }],
              null,
              'pomodoro-nudge'
            );
            playNotificationSound(getNotificationSound());
          }, 10 * 60 * 1000);
        }
      }
    };

    navigator.serviceWorker.addEventListener('message', handleMessage);
    return () => navigator.serviceWorker.removeEventListener('message', handleMessage);
  }, []);

  const showNotification = (title, body, actions = [], taskId = null, tag = 'pomodoro-timer') => {
    if (!('Notification' in window) || Notification.permission !== 'granted') return;
    const reg = swRegistrationRef.current;
    if (reg) {
      reg.showNotification(title, {
        body,
        icon: '/logo192.png',
        actions,
        data: { taskId },
        requireInteraction: actions.length > 0,
        tag,
      });
    }
  };

  useEffect(() => {
    if (!focusedTask) return;

    let interval = null;
    if (isTimerActive && timeRemaining > 0) {
      interval = setInterval(() => {
        setTimeRemaining(time => time - 1);
      }, 1000);
    } else if (isTimerActive && timeRemaining === 0) {
      setIsTimerActive(false);
      playNotificationSound(getNotificationSound());
      if (timerMode === 'pomodoro') {
        // Log the completed focus session
        if (activeSession) {
          const endTime = new Date();
          const newLog = {
            id: generateId(),
            taskId: activeSession.taskId,
            taskText: findNodeRecursive(treeData, activeSession.taskId)?.text || 'Untitled Task',
            startTime: activeSession.startTime,
            endTime: endTime,
          };
          if (endTime.getTime() - activeSession.startTime.getTime() > 5 * 60 * 1000) {
            logsHook.addLog(newLog);
          }
          setActiveSession(null);
        }

        const newCount = pomodoroCount + 1;
        setPomodoroCount(newCount);
        const pomodorosField = focusedTask.fields?.find(f => f.label === 'Pomodoros');
        const currentPoms = pomodorosField ? parseInt(pomodorosField.value, 10) : 0;
        const newPomsValue = isNaN(currentPoms) ? 1 : currentPoms + 1;

        if (pomodorosField) {
          handleUpdateField(focusedTask.id, pomodorosField.id, 'value', String(newPomsValue));
        } else {
          handleAddField(focusedTask.id, { label: 'Pomodoros', value: '1' });
        }

        showNotification(
          'Pomodoro Complete!',
          focusedTask.text || 'Untitled Task',
          [
            { action: 'newPomodoro', title: 'New Pomodoro' },
            { action: 'markFinished', title: 'Mark Finished' },
          ],
          focusedTask.id
        );

        setTimerMode(newCount % 4 === 0 ? 'longBreak' : 'shortBreak');
      } else {
        showNotification(
          'Break Over!',
          `Ready to focus on: ${focusedTask.text || 'Untitled Task'}`,
          [
            { action: 'newPomodoro', title: 'Start Focus' },
            { action: 'markFinished', title: 'Mark Finished' },
          ],
          focusedTask.id
        );
        setTimerMode('pomodoro');
      }
    }
    return () => clearInterval(interval);
  }, [isTimerActive, timeRemaining, timerMode, pomodoroCount, focusedTask, handleUpdateField, handleAddField]);

  useEffect(() => {
    const durations = getTimerDurations();
    const timeMap = { pomodoro: durations.pomodoro, shortBreak: durations.shortBreak, longBreak: durations.longBreak };
    setTimeRemaining(timeMap[timerMode]);
  }, [timerMode]);

  const handleTimerStartPause = () => {
    const newIsTimerActive = !isTimerActive;

    if (newIsTimerActive && focusedTask) {
      setActiveSession({ taskId: focusedTask.id, startTime: new Date() });
      if ('Notification' in window && Notification.permission === 'default') {
        Notification.requestPermission();
      }
      const modeLabel = timerMode === 'pomodoro' ? 'Focus' : timerMode === 'shortBreak' ? 'Short Break' : 'Long Break';
      showNotification(`${modeLabel} Started`, focusedTask.text || 'Untitled Task', [], focusedTask.id);
    } else if (!newIsTimerActive && activeSession) {
      const endTime = new Date();
      const newLog = {
        id: generateId(),
        taskId: activeSession.taskId,
        taskText: findNodeRecursive(treeData, activeSession.taskId)?.text || 'Untitled Task',
        startTime: activeSession.startTime,
        endTime: endTime,
      };
      if (endTime.getTime() - activeSession.startTime.getTime() > 5 * 60 * 1000) {
        logsHook.addLog(newLog);
      }
      setActiveSession(null);
      handleUpdate(focusedTask.id, { timeRemaining, timerMode, isTimerActive: false });
    }
    setIsTimerActive(newIsTimerActive);
  };

  const handleTimerReset = () => {
    if (!focusedTask) return;
    setIsTimerActive(false);
    const durations = getTimerDurations();
    const timeMap = { pomodoro: durations.pomodoro, shortBreak: durations.shortBreak, longBreak: durations.longBreak };
    setTimeRemaining(timeMap[timerMode]);
    if (focusedTask) {
      handleUpdate(focusedTask.id, { timeRemaining: timeMap[timerMode], timerMode, isTimerActive: false });
    }
  };


  const handleStartFocus = (taskId, autoStart = false) => {
    setFocusedTaskId(taskId);
    const task = findNodeRecursive(treeData, taskId);
    const defaultPomodoro = getTimerDurations().pomodoro;
    const mode = task?.timerMode || 'pomodoro';
    const remaining = task?.timeRemaining !== undefined ? task.timeRemaining : defaultPomodoro;
    setTimerMode(mode);
    setTimeRemaining(remaining);
    if (autoStart) {
      setIsTimerActive(true);
      setActiveSession({ taskId, startTime: new Date() });
    } else {
      setIsTimerActive(false);
    }
  };

  const handleExitFocus = () => {
    if (focusedTask) {
      if (isTimerActive && activeSession) {
        const endTime = new Date();
        const newLog = {
          id: generateId(),
          taskId: activeSession.taskId,
          taskText: findNodeRecursive(treeData, activeSession.taskId)?.text || 'Untitled Task',
          startTime: activeSession.startTime,
          endTime: endTime,
        };
        if (endTime.getTime() - activeSession.startTime.getTime() > 5 * 60 * 1000) {
          logsHook.addLog(newLog);
        }
        setActiveSession(null);
        handleUpdate(focusedTask.id, { timeRemaining, timerMode, isTimerActive: false });
      }
    }
    if (capturedTasks.length > 0) {
      setShowTriageModal(true);
    }
    setFocusedTaskId(null);
  };

  const handleCaptureTask = (text) => {
    setCapturedTasks(prev => [...prev, { id: generateId(), text }]);
  };

  const handleAddCapturedAsRoot = (text) => {
    const newId = treeDataHook.handleAddRoot(getTodayDateString());
    handleUpdate(newId, { text });
  };

  const handleAddCapturedUnderParent = (text, parentId) => {
    const newId = treeDataHook.handleAddSubtask(parentId, getTodayDateString());
    handleUpdate(newId, { text });
  };

  const handleTriageComplete = () => {
    setCapturedTasks([]);
    setShowTriageModal(false);
  };

  // Idle nudge: notify when no pomodoro is running for a configured period
  useEffect(() => {
    clearTimeout(nudgeTimeoutRef.current);
    // Only nudge when completely idle (not in focus mode, timer not active)
    if (focusedTaskId || isTimerActive) return;

    const nudgeMinutes = getNudgeMinutes();
    if (nudgeMinutes <= 0) return;
    if (!('Notification' in window) || Notification.permission !== 'granted') return;

    nudgeTimeoutRef.current = setTimeout(() => {
      showNotification(
        getRandomNudge(),
        "You haven't started this in a while.",
        [{ action: 'snooze', title: 'Remind in 10 min' }],
        null,
        'pomodoro-nudge'
      );
      playNotificationSound(getNotificationSound());
    }, nudgeMinutes * 60 * 1000);

    return () => clearTimeout(nudgeTimeoutRef.current);
  }, [focusedTaskId, isTimerActive]);

  // Schedule reminders: notify before tasks with scheduled times
  const notifiedTasksRef = useRef(new Set());
  useEffect(() => {
    if (!('Notification' in window) || Notification.permission !== 'granted') return;
    const reminderMin = getReminderMinutes();
    if (reminderMin <= 0) return;

    const checkSchedules = () => {
      const now = new Date();
      const todayStr = getTodayDateString();
      const scan = (nodes) => {
        for (const node of nodes) {
          if (node.scheduledDate === todayStr && node.scheduledTime && !node.isCompleted) {
            const [h, m] = node.scheduledTime.split(':').map(Number);
            const scheduledAt = new Date(now);
            scheduledAt.setHours(h, m, 0, 0);
            const diffMs = scheduledAt.getTime() - now.getTime();
            const diffMin = diffMs / 60000;
            if (diffMin > 0 && diffMin <= reminderMin && !notifiedTasksRef.current.has(node.id + todayStr)) {
              notifiedTasksRef.current.add(node.id + todayStr);
              showNotification(
                `Coming up in ${Math.ceil(diffMin)} min`,
                node.text || 'Untitled Task',
                [{ action: 'newPomodoro', title: 'Start Focus' }],
                node.id,
                `schedule-${node.id}`
              );
              playNotificationSound(getNotificationSound());
            }
          }
          if (node.children) scan(node.children);
        }
      };
      scan(treeData);
    };

    checkSchedules();
    const interval = setInterval(checkSchedules, 30000);
    return () => clearInterval(interval);
  }, [treeData]);

  // Background music: auto-play during focus pomodoros, pause otherwise
  useEffect(() => {
    if (focusedTaskId && isTimerActive && timerMode === 'pomodoro') {
      playBgMusic();
    } else {
      pauseBgMusic();
    }
  }, [focusedTaskId, isTimerActive, timerMode]);

  const timerProps = {
    timeRemaining,
    isTimerActive,
    timerMode,
    onStartPause: handleTimerStartPause,
    onReset: handleTimerReset,
    onSetMode: setTimerMode
  };

  const handleExport = async () => {
    try {
      let stateToExport;
      try {
        stateToExport = await api.bulkExport();
      } catch {
        stateToExport = {
          treeData: treeData,
          logs: logsHook.logs,
          memoryData: memoryDataHook.memoryData,
        };
      }
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(stateToExport, null, 2));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", `flow-backup-${new Date().toISOString().split('T')[0]}.json`);
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
    } catch (error) {
      console.error("Export failed:", error);
      alert("Failed to export data.");
    }
  };

  const handleImport = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (!window.confirm("Are you sure you want to import? This will override all your current tasks and logs.")) {
      e.target.value = null;
      return;
    }

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const importedState = JSON.parse(event.target.result);
        if (!importedState.treeData) {
          alert("Import failed: Invalid file format.");
          return;
        }

        // Import to Supabase
        try {
          await api.bulkImport(importedState);
        } catch (err) {
          console.error("Supabase import failed, applying locally:", err);
        }

        // Apply locally
        if (importedState.treeData) {
          treeDataHook.setTreeData(importedState.treeData);
        }
        if (importedState.logs && Array.isArray(importedState.logs)) {
          const revivedLogs = importedState.logs.map(log => ({
            ...log,
            startTime: new Date(log.startTime),
            endTime: new Date(log.endTime)
          }));
          logsHook.setLogs(revivedLogs);
        }
        if (importedState.memoryData) {
          memoryDataHook.setMemoryData(importedState.memoryData);
        }
        alert("Data imported successfully!");
      } catch (error) {
        console.error("Import failed:", error);
        alert("Import failed: Could not parse the file.");
      } finally {
        e.target.value = null;
      }
    };
    reader.readAsText(file);
  };

  let appState = 'idle';
  if (focusedTask) {
    if (isTimerActive) {
      appState = timerMode === 'pomodoro' ? 'focusing' : 'break';
    } else {
      appState = 'paused';
    }
  }

  const scrollbarHideStyle = `
    .no-scrollbar::-webkit-scrollbar {
      display: none;
    }
    .no-scrollbar {
      -ms-overflow-style: none;
      scrollbar-width: none;
    }
  `;

  const quillStyle = `
    .rich-text-editor .ql-toolbar {
      border-radius: 8px 8px 0 0;
      border-color: var(--color-quill-border);
    }
    .rich-text-editor .ql-container {
      border-radius: 0 0 8px 8px;
      border-color: var(--color-quill-border);
      color: var(--color-quill-text);
      min-height: 150px;
    }
    .rich-text-editor .ql-editor {
      font-size: 14px;
    }
    .rich-text-editor .ql-snow .ql-stroke {
      stroke: var(--color-quill-icon);
    }
    .rich-text-editor .ql-snow .ql-picker-label {
      color: var(--color-quill-icon);
    }
    .rich-text-editor .ql-editor.ql-blank::before {
      color: var(--color-quill-placeholder);
      font-style: italic;
      left: 1rem;
      pointer-events: none;
    }
  `;

  return (
    <ThemeContext.Provider value={themeValue}>
    <OnlineContext.Provider value={onlineStatus}>
    <TreeDataContext.Provider value={treeDataHook}>
      <LogsContext.Provider value={logsHook}>
        <MemoryContext.Provider value={memoryDataHook}>
          <style>{scrollbarHideStyle}</style>
          <style>{quillStyle}</style>
          {!treeDataHook.isLoading && !focusedTask && !isMobile && (
            <>
              <FloatingEmojis intensity="normal" customEmojis={bgEmojis} />
              {petEnabled && (
                <FlowPet
                  key={petSkin}
                  appState={appState}
                  completionCount={productivityStats.completionsToday}
                  focusSessionsToday={productivityStats.focusSessionsToday}
                  streakDays={productivityStats.streakDays}
                  treeData={treeData}
                  logs={logsHook.logs}
                />
              )}
            </>
          )}
          {treeDataHook.isLoading ? (
            <div className="min-h-screen bg-page-base flex flex-col">
              <div className="h-14 border-b border-edge-secondary flex items-center px-6 gap-4">
                <div className="shimmer h-5 w-24 rounded-md" />
                <div className="flex-1" />
                <button
                  onClick={() => treeDataHook.skipLoading()}
                  className="text-xs px-3 py-1.5 rounded-md bg-amber-500/20 text-amber-400 hover:bg-amber-500/30 transition-colors animate-fade-in-delayed opacity-0"
                >
                  Go Offline
                </button>
                <div className="shimmer h-5 w-16 rounded-md" />
                <div className="shimmer h-5 w-16 rounded-md" />
                <div className="shimmer h-5 w-16 rounded-md" />
              </div>
              <div className="flex-1 p-8 space-y-4">
                <div className="shimmer h-10 w-64 rounded-lg" />
                <div className="space-y-3 mt-6">
                  <div className="shimmer h-14 w-full rounded-xl" />
                  <div className="shimmer h-14 w-full rounded-xl" style={{ animationDelay: '0.15s' }} />
                  <div className="shimmer h-14 w-5/6 rounded-xl ml-8" style={{ animationDelay: '0.3s' }} />
                  <div className="shimmer h-14 w-5/6 rounded-xl ml-8" style={{ animationDelay: '0.45s' }} />
                  <div className="shimmer h-14 w-full rounded-xl" style={{ animationDelay: '0.6s' }} />
                  <div className="shimmer h-14 w-4/6 rounded-xl ml-8" style={{ animationDelay: '0.75s' }} />
                </div>
              </div>
            </div>
          ) : showTriageModal ? (
            <TriageModal
              capturedTasks={capturedTasks}
              treeData={treeData}
              onAddAsRoot={handleAddCapturedAsRoot}
              onAddUnderParent={handleAddCapturedUnderParent}
              onDiscard={() => {}}
              onComplete={handleTriageComplete}
            />
          ) : focusedTask ? (
            <FocusView
              task={focusedTask}
              timerProps={timerProps}
              onExit={handleExitFocus}
              appState={appState}
              capturedTasks={capturedTasks}
              onCaptureTask={handleCaptureTask}
            />
          ) : isMobile ? (
            <MobileView
              handleStartFocus={handleStartFocus}
              handleExport={handleExport}
              handleImport={handleImport}
              onLogout={onLogout}
            />
          ) : (
            <MainPage
              focusedTask={focusedTask}
              handleStartFocus={handleStartFocus}
              appState={appState}
              handleExport={handleExport}
              handleImport={handleImport}
              onLogout={onLogout}
            />
          )}
        </MemoryContext.Provider>
      </LogsContext.Provider>
    </TreeDataContext.Provider>
    </OnlineContext.Provider>
    </ThemeContext.Provider>
  );
}
